type _CharMap = {
	A: 0; a: 0; B: 1; b: 1; C: 2; c: 2; D: 3; d: 3; E: 4; e: 4;
	F: 5; f: 5; G: 6; g: 6; H: 7; h: 7; I: 8; i: 8; J: 9; j: 9;
	K: 10; k: 10; L: 11; l: 11; M: 12; m: 12; N: 13; n: 13; O: 14; o: 14;
	P: 15; p: 15; Q: 16; q: 16; R: 17; r: 17; S: 18; s: 18; T: 19; t: 19;
	U: 20; u: 20; V: 21; v: 21; W: 22; w: 22; X: 23; x: 23; Y: 24; y: 24;
	Z: 25; z: 25;
};

type _AddN<N extends number, A extends unknown[], C extends unknown[] = []> =
	C['length'] extends N ? A : _AddN<N, [...A, 0], [...C, 0]>;

type _AddStrLen<S extends string, A extends unknown[]> =
	S extends `${string}${infer R}` ? _AddStrLen<R, [...A, 0]> : A;

type _AddKey<K extends PropertyKey, A extends unknown[]> =
	K extends string
		? _AddStrLen<K,
			K extends `${infer C1}${infer C2}${string}`
				? C1 extends keyof _CharMap
					? C2 extends keyof _CharMap
						? _AddN<_CharMap[C2], _AddN<_CharMap[C1], [...A, 0]>>
						: _AddN<_CharMap[C1], [...A, 0]>
					: C2 extends keyof _CharMap
						? _AddN<_CharMap[C2], [...A, 0]>
						: [...A, 0]
				: K extends `${infer C}${string}`
					? C extends keyof _CharMap
						? _AddN<_CharMap[C], [...A, 0]>
						: [...A, 0]
					: [...A, 0]
		  >
		: [...A, 0];

type _PathAccum<
	P extends readonly PropertyKey[],
	A extends unknown[] = [],
> = P extends readonly [infer K extends PropertyKey, ...infer R extends readonly PropertyKey[]]
	? _PathAccum<R, _AddKey<K, A>>
	: A;

export type DeepReadonlyPathSlot<Path extends readonly PropertyKey[]> =
	_PathAccum<Path>['length'] extends infer N extends DeepReadonlySlot ? N : never;
